changeSet.sql:
DROP INDEX IF EXISTS idx_megaset_name_trgm;
DROP INDEX IF EXISTS idx_megaset_description_trgm;
DROP INDEX IF EXISTS idx_megaset_notes_trgm;
DROP INDEX IF EXISTS idx_megaset_set_number_trgm;
DROP INDEX IF EXISTS idx_megaset_attributes_text_trgm;

ALTER TABLE mega_set
    ADD COLUMN search_text text
    GENERATED ALWAYS AS (
        lower(f_unaccent(
            coalesce(name, '') || ' ' ||
            coalesce(description, '') || ' ' ||
            coalesce(set_number, '') || ' ' ||
            coalesce(f_jsonb_values_text(attributes), '')
        ))
    ) STORED;
